const h = $input.item.json.headers || {};
const token = h['x-meta-token'];
const account = h['x-meta-account'];
if (!token || !account) {
  $execution.abort({ message: 'Missing Meta credentials' });
}
return [{ json: { token, account } }];

const campaigns = ($('Meta Campaigns').item.json.data || []);
const insights = ($input.item.json.data || []);

const insightMap = {};
for (const ins of insights) {
  insightMap[ins.campaign_id] = ins;
}

const merged = campaigns.map(c => {
  const ins = insightMap[c.id] || {};
  const roasEntry = (ins.purchase_roas || []).find(r => r.action_type === 'omni_purchase' || r.action_type === 'purchase');
  const roas = roasEntry ? Math.round(parseFloat(roasEntry.value) * 100) / 100 : null;
  const purchaseAction = (ins.actions || []).find(a => a.action_type === 'purchase' || a.action_type === 'omni_purchase');
  const conversions = purchaseAction ? parseInt(purchaseAction.value) : 0;
  const dailyBudget = c.daily_budget ? parseFloat(c.daily_budget) / 100 : null;
  const lifetimeBudget = c.lifetime_budget ? parseFloat(c.lifetime_budget) / 100 : null;
  return {
    id: c.id,
    name: c.name,
    status: c.status === 'ACTIVE' ? 'live' : c.status === 'PAUSED' ? 'paused' : c.status === 'ARCHIVED' ? 'paused' : 'draft',
    platform: 'meta',
    objective: c.objective || null,
    daily_budget: dailyBudget,
    lifetime_budget: lifetimeBudget,
    roas: roas,
    total_spend: ins.spend ? parseFloat(ins.spend) : 0,
    impressions: ins.impressions ? parseInt(ins.impressions) : 0,
    clicks: ins.clicks ? parseInt(ins.clicks) : 0,
    ctr: ins.ctr ? Math.round(parseFloat(ins.ctr) * 100) / 100 : 0,
    conversions: conversions
  };
});

return [{ json: merged }];
